mapper.insert:
UPDATE STOCCUST SET
	  MOD_DATE = SYSDATE
	, MOD_USER_ID = #{ses.userId}
	, CUST_NM = #{CUST_NM}
	, CUST_ENG_NM = #{CUST_ENG_NM}
	, COMPANY_TYPE = #{COMPANY_TYPE}
	, CORP_TYPE = #{CORP_TYPE}
	, SCALE_TYPE = #{SCALE_TYPE}
	, IRS_NUM = #{IRS_NUM}
	, COMPANY_REG_NUM = #{COMPANY_REG_NUM}
	, ZIP_CD = #{HQ_ZIP_CD}
	, ADDR1 = #{HQ_ADDR_1}
	, ADDR2 = #{HQ_ADDR_2}
	, BUSINESS_TYPE = #{BUSINESS_TYPE}
	, INDUSTRY_TYPE = #{INDUSTRY_TYPE}
	, CEO_USER_NM = #{CEO_USER_NM}
	, TEL_NUM = #{TEL_NUM}
	, FAX_NUM = #{FAX_NUM}
	, EMAIL = #{EMAIL}
	, FOUNDATION_DATE = (#{FOUNDATION_DATE}, 'yyyyMMdd')
	, CREDIT_AGENCY_NM = #{CREDIT_AGENCY_NM}
	, CREDIT_CD = #{CREDIT_CD}
	, ATTACH_FILE_NUM = #{ATTACH_FILE_NUM}
	, ABOUT_US = #{ABOUT_US}
	, REMARK = #{REMARK}
	, STD_YYYY = #{STD_YYYY}
	, DATA_REF_CD = #{DATA_REF_CD}
	, TOT_ASSET = (#{TOT_ASSET}, 0)
	, TOT_SDEPT = (#{TOT_SDEPT}, 0)
	, TOT_FUND = (#{TOT_FUND}, 0)
	, TOT_SALES = (#{TOT_SALES}, 0)
	, NET_INCOM = (#{NET_INCOM}, 0)
	, RATE_SDEPT = (#{RATE_SDEPT}, 0)
	, CURR_ASSET = (#{CURR_ASSET}, 0)
	, CURR_SDEPT = (#{CURR_SDEPT}, 0)
	, RATE_CURR = (#{RATE_CURR}, 0)
	, RELAT_YN = #{RELAT_YN}
	, TAX_ASP_NM = #{TAX_ASP_NM}
	, TAX_SEND_TYPE = #{TAX_SEND_TYPE}
	, E_BILL_ASP_TYPE = #{E_BILL_ASP_TYPE}
	, ASSET_FILE_NUM = #{ASSET_FILE_NUM}
 WHERE GATE_CD = #{ses.gateCd}
   AND CUST_CD = #{CUST_CD}

INSERT INTO STOCCUSH (
	  GATE_CD
	, CUST_CD
	, SEQ
	, REG_DATE
	, REG_USER_ID
	, MOD_DATE
	, MOD_USER_ID
	, DEL_FLAG
	, CEO_USER_NM
	, ZIP_CD
	, ADDR_1
	, ADDR_2
	, CH_DATE
	, CH_USER_ID
)
VALUES (
	  #{ses.gateCd}
	, #{CUST_CD}
	, ((SELECT MAX(SEQ)+1 FROM STOCCUSH WHERE GATE_CD = #{ses.gateCd} AND CUST_CD = #{CUST_CD}), 0)
	, SYSDATE
	, #{ses.userId}
	, SYSDATE
	, #{ses.userId}
	, '0'
	, #{CEO_USER_NM}
	, #{HQ_ZIP_CD}
	, #{HQ_ADDR_1}
	, #{HQ_ADDR_2}
	, SYSDATE
	, #{ses.userId}
)

MERGE  TB_CO_CORP CORP
USING (SELECT #{CORP_NO} AS CORP_NO
		 ) B
 ON (CORP.CORP_NO = B.CORP_NO)
WHEN MATCHED THEN
