	 LSCHGID = #{ses.userId}
	,LSCHGDTM = SYSDATE
	,NH_CORP_CODE = #{NH_CORP_CODE}
	,CORP_NM = #{CORP_NM}
	,REP_NM = #{REP_NM}
	,BIZTP = #{BIZTP}
	,BZC = #{BZC}
	,ZIP = #{ZIP}
	,ADDR = #{ADDR}
	,DTL_ADDR = #{DTL_ADDR}
	,REP_TEL = #{REP_TEL}
	,FAX = #{FAX}
	,CORP_ROW_NO = #{CORP_ROW_NO}
	,NC_COMP_DS_C = #{NC_COMP_DS_C}
WHEN NOT MATCHED THEN
