MERGE  STOCOGDA OGDA
USING (SELECT #{ses.gateCd} AS GATE_CD
			 ,#{CUST_CD} AS BUYER_CD
			 ,#{DEPT_CD} AS DEPT_CD
			 ,#{ACCOUNT_SQ} AS ACCOUNT_SQ
		 ) B
 ON (OGDA.GATE_CD = B.GATE_CD
 AND OGDA.BUYER_CD = B.BUYER_CD
 AND OGDA.DEPT_CD = B.DEPT_CD
 AND OGDA.ACCOUNT_SQ = B.ACCOUNT_SQ)
WHEN MATCHED THEN
UPDATE SET
	  MOD_USER_ID = #{ses.userId}
	, MOD_DATE = SYSDATE
	, DEL_FLAG = #{DEL_FLAG}
	, USE_FLAG = #{USE_FLAG}
	, BANK_NM = #{BANK_NM}
	, BANK_BRANCH_OFFICE = #{BANK_BRANCH_OFFICE}
	, BANK_ACCT_NUM = #{BANK_ACCT_NUM}
	, ACCT_HOLDER_NM = #{ACCT_HOLDER_NM}
	, ACCT_NICKNAME = #{ACCT_NICKNAME}
	, ATTACH_FILE_NUM = #{ATTACH_FILE_NUM}
WHEN NOT MATCHED THEN
INSERT (
	  GATE_CD
	, BUYER_CD
	, DEPT_CD
	, ACCOUNT_SQ
	, REG_USER_ID
	, REG_DATE
	, MOD_USER_ID
	, MOD_DATE
	, DEL_FLAG
	, USE_FLAG
	, BANK_NM
	, BANK_BRANCH_OFFICE
	, BANK_ACCT_NUM
	, ACCT_HOLDER_NM
	, ACCT_NICKNAME
	, ATTACH_FILE_NUM
) VALUES (
	  #{ses.gateCd}
	, #{CUST_CD}
	, #{DEPT_CD}
	, (SELECT NVL(MAX(ACCOUNT_SQ) + 1, 1) FROM STOCOGDA WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{CUST_CD} AND DEPT_CD = #{DEPT_CD})
	, #{ses.userId}
	, SYSDATE
	, #{ses.userId}
	, SYSDATE
	, #{DEL_FLAG}
	, #{USE_FLAG}
	, #{BANK_NM}
	, #{BANK_BRANCH_OFFICE}
	, #{BANK_ACCT_NUM}
	, #{ACCT_HOLDER_NM}
	, #{ACCT_NICKNAME}
	, #{ATTACH_FILE_NUM}
)
